import json

# Get the list of financially troubled NASDAQ companies
financially_troubled = locals()['var_functions.query_db:20']

# Build a list of symbols to check
symbols_info = {}
for stock in financially_troubled:
    symbols_info[stock['Symbol']] = {
        'name': stock['Company Description'],
        'status': stock['Financial Status']
    }

symbols_to_check = list(symbols_info.keys())

# Create batch of queries (process a few at a time due to constraints)
batch_size = 5
batch_symbols = symbols_to_check[:batch_size]

print('__RESULT__:')
print(json.dumps({
    'total_symbols': len(symbols_to_check),
    'batch_symbols': batch_symbols
}))

